def find(raw) do
  found =
    Repo.one(
      from(t in Token,
        inner_join: s in Site,
        on: s.id == t.site_id,
        where: t.token_hash == ^Token.hash(raw),
        preload: [:site]
      )
    )

  if found do
    {:ok, found}
  else
    {:error, :not_found}
  end
end

