  case decode_type(type) do
    {^type, pkg_header_type, has_data} ->
      {:ok,
       %__MODULE__{
         type: pkg_header_type,
         status: decode_status(status),
         length: length - 8,
         spid: spid,
         package: package,
         window: window,
         has_data?: has_data
       }}

    {:error, _reason} = e ->
      e
  end
end

